// Gate: only Alex's messages in the 📥 Drop Zone topic of the AO Personal OS group.
// Then build the inbox card (mirrors automations/telegram-inbox/watch.sh naming).
const GROUP_CHAT_ID = 'REDACTED_GROUP_CHAT_ID';
const DROPZONE_THREAD_ID = 7;

const item = $input.first();
const m = item.json.message;
if (!m || !m.chat || String(m.chat.id) !== GROUP_CHAT_ID) return [];
if (m.message_thread_id !== DROPZONE_THREAD_ID) return [];
if (m.from && m.from.is_bot) return [];

const dt = DateTime.fromSeconds(m.date, { zone: 'Europe/Kyiv' });
const stamp = dt.toFormat('yyyyLLdd-HHmmss');
const base = `tg-${stamp}-${m.message_id}`;
const sanitize = (s) => String(s || '').replace(/[^A-Za-z0-9._-]+/g, '_').replace(/^_+|_+$/g, '').slice(0, 60);

let attachment = null;
if (m.photo && m.photo.length) attachment = `${base}-photo.jpg`;
else if (m.voice) attachment = `${base}-voice.oga`;
else if (m.audio) attachment = `${base}-` + (sanitize(m.audio.file_name) || 'audio.mp3');
else if (m.video) attachment = `${base}-video.mp4`;
else if (m.document) attachment = `${base}-` + (sanitize(m.document.file_name) || 'file');

// Base64 the downloaded media right here (no Extract From File node on this n8n version).
let mediaB64 = '';
if (attachment && item.binary && item.binary.data) {
  let buf = null;
  try { if (typeof $helpers !== 'undefined' && $helpers.getBinaryDataBuffer) buf = await $helpers.getBinaryDataBuffer(0, 'data'); } catch (e) {}
  if (!buf) { try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) {} }
  if (buf) {
    mediaB64 = buf.toString('base64');
  } else {
    const bd = item.binary.data;
    if (bd.data && bd.data.length > 64 && /^[A-Za-z0-9+/=]+$/.test(bd.data.slice(0, 64))) mediaB64 = bd.data;
  }
}
const hasMedia = !!(attachment && mediaB64);
const text = m.text || m.caption || '';

const fm = ['---', 'source: telegram-dropzone', `date: ${dt.toISO()}`, `message_id: ${m.message_id}`];
if (hasMedia) fm.push(`attachment: ${attachment}`);
fm.push('---', '');
let body = text;
if (attachment && !hasMedia) body += (body ? '\n\n' : '') + `(media ${attachment} was present but could not be downloaded)`;
if (!body) body = '(no text)';
const card = fm.join('\n') + body + '\n';

return [{
  json: {
    hasMedia,
    cardPath: `context/_inbox/${base}.md`,
    cardB64: Buffer.from(card, 'utf8').toString('base64'),
    cardMsg: `dropzone: capture ${base}`,
    mediaPath: hasMedia ? `context/_inbox/${attachment}` : '',
    mediaMsg: hasMedia ? `dropzone: capture ${attachment}` : '',
    mediaB64
  }
}];
